-- PARTE 3/6 — conteúdo das iscas 7–12
update public.blog_templum_iscas set headline='ISO 45001, o que <em>muda</em><br>de verdade no seu sistema<br>de <em>SST</em>.', subhead='A norma substituiu a OHSAS 18001 com mudanças importantes: contexto, partes interessadas, liderança e participação. Esse guia destrincha cada uma.', benefits='["<strong>Diferenças</strong> em relação à OHSAS 18001, cláusula a cláusula.","<strong>Liderança e participação</strong>: o que mudou e como aplicar.","Integração com <strong>NRs brasileiras</strong> sem retrabalho.","<strong>Caminho de implementação</strong> em fases realistas."]'::jsonb, steps='[{"num":"01","title":"Estrutura da norma","text":"Anexo SL, a lógica comum com ISO 9001 e 14001, que facilita integração."},{"num":"02","title":"Contexto e partes interessadas","text":"Cláusula 4 traduzida para SST, o que considerar e como documentar."},{"num":"03","title":"Liderança","text":"O papel da alta direção que a norma reforça, e como evidenciar."},{"num":"04","title":"Participação","text":"Como envolver trabalhadores sem virar formalidade burocrática."},{"num":"05","title":"Operação","text":"Cláusula 8 na prática: hierarquia de controle, terceiros e mudanças."},{"num":"06","title":"Avaliação e melhoria","text":"Como fechar o ciclo com auditoria, análise crítica e ação corretiva."}]'::jsonb, cta_title='ISO 45001 não é<br><em>OHSAS</em> com novo número.', cta_copy='Empresas que tentaram migrar trocando só o cabeçalho dos documentos sofreram. O guia mostra o que precisa ser de fato repensado.', cta_items='["Para empresas migrando da OHSAS 18001","Para quem vai certificar do zero","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-a-nova-iso-45001';
update public.blog_templum_iscas set headline='Análise crítica que<br><em>dá decisão</em>, não que<br>cumpre <em>cláusula</em>.', subhead='A reunião de análise crítica é uma das cláusulas que mais leva não-conformidade na auditoria. Esse guia mostra como transformar exigência em momento de gestão real.', benefits='["<strong>Pauta padrão</strong> alinhada com a cláusula 9.3.","<strong>Entradas obrigatórias</strong> e como prepará-las antecipadamente.","<strong>Decisões esperadas</strong>, e como documentar sem inventar.","Modelo de <strong>ata</strong> que sustenta auditoria."]'::jsonb, steps='[{"num":"01","title":"Pauta","text":"Estrutura mínima da reunião que cobre todas as entradas exigidas."},{"num":"02","title":"Entradas","text":"Indicadores ambientais, ações, NCs, partes interessadas, como preparar."},{"num":"03","title":"Condução","text":"Como conduzir para gerar decisão, não só apresentação."},{"num":"04","title":"Saídas","text":"Quais decisões a norma espera e como registrar de forma defensável."},{"num":"05","title":"Ata","text":"Modelo aplicável que satisfaz auditor e equipe interna."},{"num":"06","title":"Acompanhamento","text":"Como manter as ações da análise crítica vivas até a próxima reunião."}]'::jsonb, cta_title='Reunião de uma hora<br>que <em>vale o ano todo</em>.', cta_copy='Análise crítica bem feita é a diferença entre sistema vivo e sistema de fachada. O guia mostra como fazer com eficiência.', cta_items='["Modelo de pauta e ata pronto","Aplicável também a ISO 9001 e 45001","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Vale para ISO 9001 e ISO 45001 também?","a":"Sim. A cláusula 9.3 é a mesma estrutura nas três normas. Você pode adaptar facilmente."}]'::jsonb where slug='analise-critica-pela-direcao-iso-14001-guia-completo-e-pratico';
update public.blog_templum_iscas set headline='PBQP-H sem mistério,<br>do <em>nível</em> à certificação,<br>passo a passo.', subhead='Construtoras que querem financiamento da Caixa precisam de PBQP-H. Esse guia explica os níveis, os requisitos e o caminho mais curto pra certificação.', benefits='["Diferença entre <strong>níveis A, B, C, D</strong> e qual buscar.","<strong>Documentação</strong> obrigatória e como preparar.","Integração com <strong>ISO 9001</strong> sem duplicar esforço.","Caminho realista de <strong>certificação em 6-12 meses</strong>."]'::jsonb, steps='[{"num":"01","title":"O que é PBQP-H","text":"Programa do governo federal, origem, lógica e por que existe."},{"num":"02","title":"Níveis e exigências","text":"A, B, C, D, diferença de cada um e qual escolher para sua construtora."},{"num":"03","title":"Pré-requisitos","text":"O que precisa estar pronto antes de abrir o processo de certificação."},{"num":"04","title":"Documentação","text":"Lista enxuta do que precisa ser elaborado, revisado e aprovado."},{"num":"05","title":"Auditoria","text":"Como funcionam as etapas, fase 1, fase 2 e manutenção."},{"num":"06","title":"Acesso ao crédito","text":"Como o PBQP-H destrava aprovação da Caixa em programas como MCMV."}]'::jsonb, cta_title='PBQP-H é o <em>passaporte</em><br>pro crédito da Caixa.', cta_copy='Sem certificação, sua construtora fica de fora dos principais programas habitacionais. Esse guia mostra o caminho mais rápido pra entrar.', cta_items='["Aplicável a construtoras de todos os portes","Conecta-se a ISO 9001 sem retrabalho","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Quanto tempo leva a certificação?","a":"Tipicamente entre 6 e 12 meses, dependendo da maturidade atual e do nível buscado."}]'::jsonb where slug='e-book-guia-pbqp-h';
update public.blog_templum_iscas set headline='PBQP-H e Norma de<br>Desempenho, <em>juntas</em><br>no mesmo projeto.', subhead='PBQP-H e NBR 15575 cobram coisas parecidas mas com lógicas diferentes. Esse guia ensina a estruturar projeto e obra atendendo as duas em paralelo, sem trabalhar duas vezes.', benefits='["<strong>Pontes</strong> entre PBQP-H e NBR 15575.","Como evitar <strong>retrabalho</strong> de projeto e documentação.","Critérios de <strong>desempenho</strong> aplicados na prática.","Plano único que atende <strong>Caixa e desempenho</strong>."]'::jsonb, steps='[{"num":"01","title":"Visão geral","text":"O que cada exigência pede, e onde elas se sobrepõem."},{"num":"02","title":"Critérios de desempenho","text":"Estrutural, vedação, pisos, fachadas, instalações e durabilidade."},{"num":"03","title":"Projeto integrado","text":"Como o projeto absorve as duas exigências sem virar dois projetos."},{"num":"04","title":"Obra e controle","text":"O que mudar no canteiro para que desempenho não vire surpresa pós-entrega."},{"num":"05","title":"Documentação","text":"Registros que servem para PBQP-H e para o manual de uso e manutenção."},{"num":"06","title":"Vida útil e garantia","text":"Como tratar a vida útil de projeto sem expor sua construtora a passivo."}]'::jsonb, cta_title='Norma de Desempenho<br>chegou pra <em>ficar</em>.', cta_copy='Construtoras que tratam PBQP-H e NBR 15575 como sistemas separados acabam atrasando entrega e expondo-se a passivos. O guia mostra a integração.', cta_items='["Para construtoras de incorporação e MCMV","Reduz retrabalho de projeto","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-pbqp-h-e-a-norma-de-desempenho';
update public.blog_templum_iscas set headline='Mitos e verdades do<br>PBQP-H, o que <em>você</em><br>ainda não <em>sabia</em>.', subhead='Toda construtora ouve histórias sobre PBQP-H, algumas verdadeiras, muitas exageradas. Este ebook separa o que importa do que é boato de corredor.', benefits='["Por que <strong>não é só burocracia</strong>, apesar de parecer.","Quanto <strong>realmente custa</strong> certificar.","<strong>Tempo</strong> realista até a certificação.","Como <strong>não perder</strong> a certificação depois de obtida."]'::jsonb, steps='[{"num":"01","title":"Mito do custo","text":"Quanto custa de verdade, e quanto a empresa economiza depois."},{"num":"02","title":"Mito do tempo","text":"Quanto tempo é realista, e onde construtoras se atrasam."},{"num":"03","title":"Mito da papelada","text":"Quanto é papelada de fato e quanto é só má implementação."},{"num":"04","title":"Mito do nível A","text":"Por que muita construtora não precisa começar pelo A."},{"num":"05","title":"Mito da manutenção","text":"O que dá trabalho pra manter, e o que se automatiza."},{"num":"06","title":"Verdade central","text":"PBQP-H é o passaporte da Caixa. Sem ele, programa nenhum aprova."}]'::jsonb, cta_title='Decisão informada<br><em>economiza</em> tempo e dinheiro.', cta_copy='Comece o processo de certificação sabendo o que esperar. Esse guia faz isso em 1 hora de leitura.', cta_items='["Leitura rápida","Cases reais de construtoras","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-mitos-e-verdades-do-pbqp-h';
update public.blog_templum_iscas set headline='Indicadores de obra que<br><em>cabem</em> na rotina,<br>e <em>movem</em> o resultado.', subhead='Obra que não mede, não controla. Esse guia mostra os indicadores que de fato importam, como coletar com pouco esforço e como traduzir em ação no canteiro.', benefits='["Indicadores de <strong>produtividade, perda e prazo</strong>.","Modelo de <strong>coleta enxuta</strong> que não vira papelada.","Como ler dados <strong>antes do mês fechar</strong>.","Ligação direta com <strong>plano de obra</strong> e PBQP-H."]'::jsonb, steps='[{"num":"01","title":"O que medir","text":"Indicadores que de fato impactam custo, prazo e qualidade na obra."},{"num":"02","title":"Coleta enxuta","text":"Como capturar dado sem virar enchedor de planilha, quem coleta e quando."},{"num":"03","title":"Análise no ritmo certo","text":"Frequência de leitura que permite ação antes do problema crescer."},{"num":"04","title":"Decisão no canteiro","text":"Como traduzir indicador em ação concreta do engenheiro/encarregado."},{"num":"05","title":"Indicadores e PBQP-H","text":"Quais indicadores satisfazem requisito da norma sem trabalho extra."},{"num":"06","title":"Painel mensal","text":"Modelo de painel que a diretoria entende em 5 minutos."}]'::jsonb, cta_title='Obra que <em>mede</em><br>obra que <em>controla</em>.', cta_copy='Cada ponto percentual de perda evitada é margem que volta pro caixa. O guia mostra como medir sem virar burocracia.', cta_items='["Aplicável a obra residencial e comercial","Conecta com requisitos do PBQP-H","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='gestao-de-indicadores-em-obras-eficiencia-e-resultados-reais';
